parameters.jsCode:
const rawBody = $('📥 Webhook').first().json;
const req = rawBody.body || rawBody;

const employees = ($('👤 Read Employees3').all() || []).map(i => i.json);
const shifts    = ($('📅 Read Shifts3').all()    || []).map(i => i.json);
const dayoffRaw = ($('🛑 Read DayOffs').all()   || []).map(i => i.json);

const WEEKDAYS = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'];
const MAX_OFF  = 2;

function toISO(s) {
  if (!s) return null;
  const p = String(s).split('-');
  if (p.length !== 3) return null;
  const [a,b,c] = p;
  return a.length === 4
    ? `${a}-${b.padStart(2,'0')}-${c.padStart(2,'0')}`
    : `${c.padStart(4,'0')}-${b.padStart(2,'0')}-${a.padStart(2,'0')}`;
}

function weekday(d) {
  if (!d) return null;
  const dt = new Date(d + 'T00:00:00');
  return isNaN(dt) ? null : WEEKDAYS[dt.getDay()];
}

function addDays(d, n) {
  if (!d) return null;
  const dt = new Date(d + 'T00:00:00');
  if (isNaN(dt)) return null;
  dt.setDate(dt.getDate() + n);
  return dt.toISOString().split('T')[0];
}

function getISOWeek(d) {
  const dt = new Date(d + 'T00:00:00');
  dt.setHours(0,0,0,0);
  dt.setDate(dt.getDate() + 3 - (dt.getDay() + 6) % 7);
  const week1 = new Date(dt.getFullYear(), 0, 4);
  return 1 + Math.round(((dt.getTime() - week1.getTime()) / 86400000 - 3 + (week1.getDay() + 6) % 7) / 7);
}

function getWeekYear(d) {
  const dt = new Date(d + 'T00:00:00');
  dt.setDate(dt.getDate() + 3 - (dt.getDay() + 6) % 7);
  return dt.getFullYear();
}

const dayoffs = dayoffRaw.map(r => ({ ...r, DateISO: toISO(r.Date) }));

// ── Validate employee ─────────────────────────────────────────────
const employee = employees.find(e => e.Employee_ID === req.employee_id) || null;
if (!employee) {
  return [{ json: { valid: false, has_conflicts: false, can_submit: false, conflicts: [], alternatives: [],
    error: 'INVALID_EMPLOYEE', error_message: `Employee ID "${req.employee_id}" not found.` } }];
}

// ── Validate date ─────────────────────────────────────────────────
const reqDate = toISO(req.request_date);
if (!reqDate) {
  return [{ json: { valid: false, has_conflicts: false, can_submit: false, conflicts: [], alternatives: [],
    error: 'INVALID_DATE', error_message: `Date "${req.request_date}" is invalid.` } }];
}

const today = new Date(); today.setHours(0,0,0,0);
if (new Date(reqDate + 'T00:00:00') < today) {
  return [{ json: { valid: false, has_conflicts: false, can_submit: false, conflicts: [], alternatives: [],
    error: 'PAST_DATE', error_message: 'Cannot request a day-off for a past date.' } }];
}

const empId = req.employee_id;
const empApproved    = dayoffs.filter(r => r.Employee_ID === empId && r.Status === 'Approved' && r.DateISO);
const othersOffToday = dayoffs.filter(r => r.DateISO === reqDate && r.Status === 'Approved' && r.Employee_ID !== empId);
const shiftToday     = shifts.find(s => s.Employee_ID === empId && toISO(s.Date) === reqDate);
const pendingDup     = dayoffs.find(r => r.Employee_ID === empId && r.DateISO === reqDate && r.Status === 'Pending');

const conflicts = [];

// 1. Duplicate
if (empApproved.find(a => a.DateISO === reqDate)) {
  conflicts.push({ rule: 'Duplicate', severity: 'Critical',
    detail: `You already have an approved day-off on ${reqDate}.` });
}

// 2. Pending duplicate
if (pendingDup) {
  conflicts.push({ rule: 'Pending Request Exists', severity: 'Critical',
    detail: `You already have a pending request for ${reqDate}.` });
}

// 3. Shift conflict
if (shiftToday && shiftToday.Shift_Type !== 'OFF') {
  conflicts.push({ rule: 'Shift Conflict', severity: 'Critical',
    detail: `You are scheduled for a ${shiftToday.Shift_Type} shift on ${reqDate}.` });
}

// 4. Max 2 employees off per day
if (othersOffToday.length >= MAX_OFF) {
  conflicts.push({ rule: 'Maximum Capacity', severity: 'Critical',
    detail: `${othersOffToday.length}/${MAX_OFF} other employees are already off on this date. No slots remaining.` });
}

// 5. No consecutive days off
const dayBefore = addDays(reqDate, -1);
const dayAfter  = addDays(reqDate, 1);
const consecutive = empApproved.find(a => a.DateISO === dayBefore || a.DateISO === dayAfter);
if (consecutive) {
  const which = consecutive.DateISO === dayBefore ? dayBefore : dayAfter;
  const label = consecutive.DateISO === dayBefore ? 'the day before' : 'the day after';
  conflicts.push({ rule: 'Consecutive Days Off', severity: 'Critical',
    detail: `You already have an approved day-off on ${which} (${label}). Consecutive days off are not allowed.` });
}

// 6. Max 1 day off per week
const reqWeek = getISOWeek(reqDate);
const reqWYear = getWeekYear(reqDate);
const sameWeek = empApproved.find(a => a.DateISO && getWeekYear(a.DateISO) === reqWYear && getISOWeek(a.DateISO) === reqWeek);
if (sameWeek) {
  conflicts.push({ rule: 'Weekly Limit', severity: 'Critical',
    detail: `You already have an approved day-off this week on ${sameWeek.DateISO}. Only 1 day off per week is allowed.` });
}

// 7. No same weekday repeat
const reqWeekday = weekday(reqDate);
const sameWeekday = empApproved.find(a => a.DateISO && weekday(a.DateISO) === reqWeekday && a.DateISO !== reqDate);
if (sameWeekday) {
  conflicts.push({ rule: 'Same Weekday Repeat', severity: 'Critical',
    detail: `You already took a ${reqWeekday} off on ${sameWeekday.DateISO}. Taking off on the same weekday repeatedly is not allowed.` });
}

const hasConflicts = conflicts.length > 0;

// ── Alternative dates (must pass ALL rules) ───────────────────────
const alternatives = [];
let cursor = addDays(reqDate, 1);
let tries  = 0;
while (alternatives.length < 5 && tries < 60) {
  tries++;
  if (!cursor) break;

  const cWeekday  = weekday(cursor);
  const cWeek     = getISOWeek(cursor);
  const cWYear    = getWeekYear(cursor);
  const cBefore   = addDays(cursor, -1);
  const cAfter    = addDays(cursor, 1);
  const offCount  = dayoffs.filter(r => r.DateISO === cursor && r.Status === 'Approved').length;

  const ok_shift    = !shifts.find(s => s.Employee_ID === empId && toISO(s.Date) === cursor && s.Shift_Type !== 'OFF');
  const ok_dup      = !empApproved.find(a => a.DateISO === cursor);
  const ok_cap      = offCount < MAX_OFF;
  const ok_consec   = !empApproved.find(a => a.DateISO === cBefore || a.DateISO === cAfter);
  const ok_week     = !empApproved.find(a => a.DateISO && getWeekYear(a.DateISO) === cWYear && getISOWeek(a.DateISO) === cWeek);
  const ok_weekday  = !empApproved.find(a => a.DateISO && weekday(a.DateISO) === cWeekday);

  if (ok_shift && ok_dup && ok_cap && ok_consec && ok_week && ok_weekday) {
    alternatives.push({
      date:     cursor,
      weekday:  cWeekday,
      capacity: `${offCount}/${MAX_OFF}`,
      shift:    shifts.find(s => s.Employee_ID === empId && toISO(s.Date) === cursor)?.Shift_Type || 'OFF'
    });
  }
  cursor = addDays(cursor, 1);
}

return [{ json: {
  valid:         true,
  has_conflicts: hasConflicts,
  can_submit:    !hasConflicts,
  conflicts,
  employee,
  request: {
    employee_id:   req.employee_id,
    employee_name: req.employee_name || employee.Name,
    request_date:  reqDate,
    reason:        req.reason || 'Not provided',
    notes:         req.notes  || ''
  },
  alternatives,
  timestamp: new Date().toISOString()
}}];

parameters.text:
=You are an HR scheduling assistant. Analyze this day-off request and respond with a JSON decision.

FULL REQUEST CONTEXT:
{{ JSON.stringify($json) }}

Employee: {{ $json.employee.Name }} (ID: {{ $json.request.employee_id }})
Department: {{ $json.employee.Department }}
Position: {{ $json.employee.Position }}
Requested Date: {{ $json.request.request_date }}
Reason: {{ $json.request.reason }}
Has Conflicts: {{ $json.has_conflicts }}

Conflicts ({{ $json.conflicts.length }} total):
{{ $json.conflicts.length > 0 ? $json.conflicts.map(c => '- [' + c.severity + '] ' + c.rule + ': ' + c.detail).join('\n') : 'None - APPROVE this request' }}

Alternative dates if needed:
{{ $json.alternatives.map(a => a.date + ' (' + a.weekday + ') capacity: ' + a.capacity).join('\n') || 'None found' }}

STRICT DECISION RULES:
1. conflicts array is EMPTY → decision MUST be "APPROVE"
2. conflicts array has ANY item → decision MUST be "REJECTED"
3. Address {{ $json.employee.Name }} by first name
4. Maximum Capacity: say another employee is already booked off that day
5. Duplicate: say they already have approved leave on that date
6. Pending Request Exists: say they already have a pending request
7. Shift Conflict: say they are scheduled to work that day
8. Consecutive Days Off: say they already have a day off right next to that date
9. Weekly Limit: say they already used their day off this week
10. Same Weekday Repeat: say they already took that weekday off before
11. Never reveal other employee names or IDs
12. If rejecting, MUST mention first alternative: {{ $json.alternatives[0] ? $json.alternatives[0].date + ' (' + $json.alternatives[0].weekday + ')' : 'no date available' }}
13. Keep messages warm, 2-3 sentences max
14. suggested_date MUST be: {{ $json.alternatives[0] ? $json.alternatives[0].date : null }}

Respond ONLY with raw JSON (no markdown, no code fences):
{"decision":"APPROVE","message":"...","suggested_date":"{{ $json.alternatives[0] ? $json.alternatives[0].date : 'null' }}","reasoning":"one sentence"}

parameters.jsCode:
const aiOutput = $input.first().json;
let ctx = {};
try { ctx = $('🔍 Validate & Check').first().json; } catch(e) { ctx = {}; }

let ai;
try {
  const raw = (aiOutput.output || aiOutput.text || JSON.stringify(aiOutput))
    .replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();
  const match = raw.match(/\{[\s\S]*"decision"[\s\S]*\}/);
  ai = JSON.parse(match ? match[0] : raw);
} catch(e) {
  const rejected = (ctx.conflicts || []).length > 0;
  const firstName = (ctx.employee?.Name || 'there').split(' ')[0];
  ai = {
    decision: rejected ? 'REJECTED' : 'APPROVE',
    message: rejected
      ? `Sorry ${firstName}, your request could not be approved due to a scheduling conflict.`
      : `Great news ${firstName}! Your day-off request has been approved.`,
    suggested_date: ctx.alternatives?.[0]?.date || null,
    reasoning: 'Automated decision'
  };
}

const approved = (ai.decision || '').toUpperCase() === 'APPROVE';

return [{ json: {
  can_submit:    approved,
  employee:      ctx.employee     || {},
  request:       ctx.request      || {},
  timestamp:     ctx.timestamp    || new Date().toISOString(),
  conflicts:     ctx.conflicts    || [],
  alternatives:  ctx.alternatives || [],
  ai_decision: {
    reasoning:      ai.reasoning      || '',
    message:        ai.message        || '',
    suggested_date: ai.suggested_date || null
  }
}}];

